import '../lib/package_release.dart';
import '../lib/release_selector.dart';
import '../lib/semantic_version.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

PackageRelease release(String version) {
  return PackageRelease.fromText('renderer', version);
}

void main() {
  check(
    SemanticVersion.parse(
          '1.0.0-alpha.1',
        ).compareTo(SemanticVersion.parse('1.0.0-alpha.beta')) <
        0,
    'numeric identifiers precede nonnumeric identifiers',
  );
  check(
    SemanticVersion.parse(
          '1.0.0-alpha',
        ).compareTo(SemanticVersion.parse('1.0.0-alpha.1')) <
        0,
    'a shorter equal prerelease sequence has lower precedence',
  );
  check(
    SemanticVersion.parse(
          '1.0.0+build.1',
        ).compareTo(SemanticVersion.parse('1.0.0+build.9')) ==
        0,
    'build metadata does not change version precedence',
  );

  final selected = ReleaseSelector().bestCompatible(<PackageRelease>[
    release('2.0.0-rc.1'),
    release('2.0.0-rc.2'),
    release('2.0.0-rc.10'),
    release('2.0.0'),
    release('2.1.0'),
  ], '>=2.0.0-rc.2 <2.0.0');
  check(
    selected?.version.toString() == '2.0.0-rc.10',
    'prerelease precedence and bounded selection compose correctly',
  );

  print('final tests passed');
}
